from typing import List, Dict, TextIOfrom .e_cov_reporttype import ECoverageReportTypefrom ..exceptions import (	FocalProjectNotSetError,	DataFileNotSetError,	ReportTypeNotSetError)class CoverageRcWriter:	"""		Represents an object capable of writing "coverage.rc" files (related to coverage.py		software) in which the coverage calculation options chosen are specified.	"""		def __init__(self):		"""			Creates a new CoverageRcWriter		"""		self._focal_dir: str = None		self._excl_paths: List[str] = None		self._datafile_path: str = "coverage.gtsai.data"		self._report_type: ECoverageReportType = ECoverageReportType.JSON		self._other_options: Dict[str, Dict[str, str]] = dict()					def set_focal_project(			self,			focal_dirname: str,			excluded: List[str] = None,	):		"""			Sets the focal project related to the "coverage.rc" file that			has to be written						Parameters            ----------                focal_dirname: str                    A string representing the directory of the Focal Project Root Path for the Focal project									excluded: List[str]					Opzionale. Default = `None`. A list of strings containing the sub-paths					to exclude from coverage evaluation.					Each path is relative to the Full Root Project Path								Raises			------				ValueError                    Occurs if:                                            - The `focal_root` parameter is `None` or an empty string                        - The `excluded` parameter is an empty list		"""		if (focal_dirname is None) or (focal_dirname == ""):			raise ValueError()		if excluded is not None:			if len(excluded) == 0 :				raise ValueError()		self._focal_dir = focal_dirname		self._excl_paths = excluded					def set_option(			self,	        section: str,			option: str,			value: str	):		"""			Sets the value of a coverage.rc option that is not "omit" or "source".            If value is `None`, the previous value of the option is cleared.                        Parameters            ----------				section: str                    A string containing the name of the section to which the option                    being set or cleared belongs									option: str                    A string containing the name of the option to be set or cleared                                    value: str                    A string containing the value to be set for the option, or `None` to request                    its removal								Raises:            ------                ValueError                    Occurs if:                        - The `section` parameter is `None` or an empty string                        - The `option` parameter is `None` or an empty string						- The `option` parameter is "omit" or "source" (and `section` is "run" or "report")                        - The `value` parameter is an empty string		"""		if (value == ""):			raise ValueError()		if (section is None) or (section == ""):			raise ValueError()		if ((option is None) or (option == "") or			((section in ["run", "report"]) and (option in ["omit", "source"]))):			raise ValueError()		if value is not None:			if self._other_options.get(section, None) is None:				self._other_options[section] = dict()			self._other_options[section][option] = value		else:			self._other_options[section].pop(option, None)							def write_rcfile(			self,			rcfile_path: str,	        use_relpaths: bool = True	):		"""			Writes the desired coverage settings to the "coverage.rc" file            at the specified path                        Parameters            ----------                rcfile_path: str                    A string representing the path to the "coverage.rc" file to be created									use_relpaths: bool                    Optional. Default = `True`. A boolean indicating whether coverage.py should                    use relative paths to refer to the modules for which it has calculated coverage								Raises            ------                ValueError                    Occurs if the `rcfile_path` parameter is None                                    DataFileNotSetError                    Occurs if no							FocalProjectNotSetError                    Occurs if no focal project has been set before                    calling this operation                                    ReportTypeNotSetError                    Occurs if no report type has been set that                    coverage.py is to produce before calling this operation		"""		if rcfile_path is None:			raise ValueError()		if self._datafile_path is None:			raise DataFileNotSetError()		if self._focal_dir is None:			raise FocalProjectNotSetError()		if self._report_type is None:			raise ReportTypeNotSetError()				with open(rcfile_path, "w") as fpcovrc:			fpcovrc.write("[run]\n")			fpcovrc.write(f"source = {self._focal_dir}\n")			fpcovrc.write(f"data_file = {self._datafile_path}\n")			fpcovrc.write(f"relative_files = {use_relpaths}\n")			fpcovrc.write("\n")			self._write_omits(fpcovrc)			fpcovrc.write("\n")						if self._excl_paths is not None:				fpcovrc.write("[report]\n")				self._write_omits(fpcovrc)			sect_dict: Dict[str, str]						for section in self._other_options.keys():				sect_dict = self._other_options[section]				fpcovrc.write("\n")				fpcovrc.write(f"[{section}]\n")				for option in sect_dict.keys():					fpcovrc.write(f"{option} = {sect_dict[option]}\n")			fpcovrc.flush()							##	============================================================	##						PRIVATE METHODS	##	============================================================			def _write_omits(self, fp_covrc: TextIO):		"""			Writes the excluded paths to the coverage.rc file being created.                        `.flush()` is not called                        Parameters            ----------				fp_covrc: TextIO                    A file pointer, opened for writing, representing the coverage.rc file                    that is being created		"""		if self._excl_paths is not None:			fp_covrc.write("omit = \n")			for excl_path in self._excl_paths:				fp_covrc.write(f"\t{excl_path}\n")